     {
-        assert(m_pos + src.size() <= m_data.size());
+        if (src.size() > m_data.size() - m_pos) {
+            throw std::ios_base::failure("SpanWriter::write(): exceeded buffer size");
+        }
         memcpy(m_data.data() + m_pos, src.data(), src.size());
